import{_ as e,o as r,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const o="/images/76f8ee2715f9.png",f=JSON.parse('{"title":"AIUI 平台介绍","description":"","frontmatter":{"title":"AIUI 平台介绍"},"headers":[],"relativePath":"platform-service/overview.md","filePath":"platform-service/overview.md","lastUpdated":null}'),i={name:"platform-service/overview.md"};function l(h,a,p,s,u,c){return r(),t("div",null,[...a[0]||(a[0]=[n('<h2 id="平台简介" tabindex="-1">平台简介 <a class="header-anchor" href="#平台简介" aria-label="Permalink to &quot;平台简介&quot;">​</a></h2><p>AIUI是科大讯飞2015年推出的自然语言理解为核心的全链路人机交互平台，平台汇聚了<strong>大模型、降噪算法、声音、图像、数字虚拟人、硬件模组</strong>等人机交互全链路软硬件核心能力，可以快速的让AI硬件接入大模型语音交互，让设备听得清、能理解、会思考、懂执行。AIUI是大模型时代下重要的语音入口，不断探索人机交互的新范式，赋能新一代AI硬件！</p><p>目前AIUI平台已经整合的行业方案有:儿童玩具、儿童教育、语音点歌、智能投影、智能鼠标、多语种AI透明屏、移动数字人、大屏调度、服务机器人、营销机器人、智慧轨道交通。</p><h3 id="儿童玩具" tabindex="-1">儿童玩具 <a class="header-anchor" href="#儿童玩具" aria-label="Permalink to &quot;儿童玩具&quot;">​</a></h3><p>情感陪伴、心智启蒙</p><p><a href="https://aiui.xfyun.cn/solution/child-toys?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="儿童教育" tabindex="-1">儿童教育 <a class="header-anchor" href="#儿童教育" aria-label="Permalink to &quot;儿童教育&quot;">​</a></h3><p>有料、有趣</p><p><a href="https://aiui.xfyun.cn/solution/child-education?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="语音点歌" tabindex="-1">语音点歌 <a class="header-anchor" href="#语音点歌" aria-label="Permalink to &quot;语音点歌&quot;">​</a></h3><p>免唤醒点播</p><p><a href="https://aiui.xfyun.cn/solution/ktv?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="智能投影" tabindex="-1">智能投影 <a class="header-anchor" href="#智能投影" aria-label="Permalink to &quot;智能投影&quot;">​</a></h3><p>定向打磨影视领域</p><p><a href="https://aiui.xfyun.cn/solution/reflection?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="智能鼠标" tabindex="-1">智能鼠标 <a class="header-anchor" href="#智能鼠标" aria-label="Permalink to &quot;智能鼠标&quot;">​</a></h3><p>提升办公效率</p><p><a href="https://aiui.xfyun.cn/solution/mouse?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="多语种ai透明屏" tabindex="-1">多语种AI透明屏 <a class="header-anchor" href="#多语种ai透明屏" aria-label="Permalink to &quot;多语种AI透明屏&quot;">​</a></h3><p>服务窗口跨语言沟通</p><p><a href="https://aiui.xfyun.cn/solution/transparent-screen?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="移动数字人" tabindex="-1">移动数字人 <a class="header-anchor" href="#移动数字人" aria-label="Permalink to &quot;移动数字人&quot;">​</a></h3><p>智能导览</p><p><a href="https://aiui.xfyun.cn/solution/mobile-digital-person?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="大屏调度" tabindex="-1">大屏调度 <a class="header-anchor" href="#大屏调度" aria-label="Permalink to &quot;大屏调度&quot;">​</a></h3><p>复杂页面一语直达</p><p><a href="https://aiui.xfyun.cn/solution/screen?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="服务机器人" tabindex="-1">服务机器人 <a class="header-anchor" href="#服务机器人" aria-label="Permalink to &quot;服务机器人&quot;">​</a></h3><p>多模态交互更拟人</p><p><a href="https://aiui.xfyun.cn/solution/robot?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="营销机器人" tabindex="-1">营销机器人 <a class="header-anchor" href="#营销机器人" aria-label="Permalink to &quot;营销机器人&quot;">​</a></h3><p>大模型零售</p><p><a href="https://aiui.xfyun.cn/solution/smart-retail?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h3 id="智能轨道交通" tabindex="-1">智能轨道交通 <a class="header-anchor" href="#智能轨道交通" aria-label="Permalink to &quot;智能轨道交通&quot;">​</a></h3><p>适用公共高噪环境</p><p><a href="https://aiui.xfyun.cn/solution/subway?chan=AIUI&amp;way=menu" target="_blank" rel="noreferrer">查看详情</a></p><h2 id="" tabindex="-1">&gt;&gt;&gt; <a class="header-anchor" href="#" aria-label="Permalink to &quot;&gt;&gt;&gt;&quot;">​</a></h2><h2 id="aiui介绍" tabindex="-1">AIUI介绍 <a class="header-anchor" href="#aiui介绍" aria-label="Permalink to &quot;AIUI介绍&quot;">​</a></h2><p>AIUI 是一套人机交互解决方案，整合了<strong>语音唤醒、语音识别、大模型语义、语音合成、内容信源</strong>等能力，具备<strong>多模态唤醒、虚拟人驱动、多语种识别、超拟人合成、声音复刻</strong>等特性。</p><p>对外提供SDK、WebSocket、硬件模组等多种集成方式，广泛应用于手机、电视、机器人、扫读笔、语音购票等智能硬件设备上。接入集成简单，硬件模组开箱即用。</p><p>**- SDK：Android、iOS、Windows、Linux</p><ul><li>API：WebSocket API**</li></ul><p><img src="'+o+'" alt="示例图片"></p>',43)])])}const m=e(i,[["render",l]]);export{f as __pageData,m as default};
